SELECT id, category, keyword, content, difficulty, create_time FROM knowledge_point WHERE (keyword LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))
AND category = #{category}
ORDER BY CASE WHEN keyword = #{keyword} THEN 0 WHEN keyword LIKE CONCAT(#{keyword}, '%') THEN 1 ELSE 2 END, id ASC LIMIT #{limit}

SELECT id, category, keyword, content, difficulty, create_time
FROM knowledge_point
WHERE category = #{category}
ORDER BY id ASC
LIMIT #{limit}
